VALUES
  ('elementary-0a2fc18c-moex-00713', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列事件何者為人民不服時可提起訴願的標的？', '["稅捐稽徵機關對業者實施實地查核之行為", "甲機關聘僱臨時人員所生薪資給付不足之爭議", "丙所有之土地被乙機關徵收而對徵收價格不服之爭議", "丁警員執行勤務不慎駕車撞傷人民戊所生的糾紛"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00714', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '甲夫乙妻結婚多年，無子女。甲尚有祖父丙、祖母丁。甲死亡時，丁依法辦理拋棄繼承。乙之應繼分為 多少？', '["2/3", "1/2", "1/3", "1/4"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00715', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於民事訴訟上和解，何者錯誤？', '["土地疆界糾紛之訴訟，得成立訴訟上和解", "法院調解成立者，與訴訟上和解有同一之效力", "當事人就未聲明之事項成立和解者，不得為執行名義", "當事人於和解之意思已甚接近，得聲請法院於當事人表明之範圍內，定和解方案，於法院將和解方案 送達兩造時，視為和解成立"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00716', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '違反行政法上義務，得予行政處罰之法源依據，下列何者錯誤？', '["財政部函釋", "法律明文授權訂定之法規命令", "法律", "地方自治條例"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00717', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於民事訴訟法上公開審理、言詞審理及直接審理原則之敘述，何者正確？', '["言詞辯論，應由訴訟代理人以言詞聲明當事人與關係人人數，以及相關證據資料為其程序之開始", "當事人應就訴訟關係，為事實上之陳述，其訴訟代理人應就訴訟關係，為法律上之陳述。兩者相異者， 以訴訟代理人之陳述為準", "法官非參與為判決基礎之辯論者，不得參與判決", "原告提出之攻擊或防禦方法，涉及被告之營業秘密者，僅得由法院以職權逕行裁定為審理不公開與判 決不公開"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00718', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列有關訊問刑事被告應告知事項之敘述，何者正確？', '["被告所犯罪名經告知後，如有變更，不必再告知", "被告犯想像競合犯裁判上一罪之案件，只要告知重罪罪名即可", "告知得選任辯護人", "被告得保持緘默，亦得說謊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00719', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '甲將其位於臺中之房屋借給好友乙1年，係因乙獲臺中之A公司聘用，然而乙須通過試用期3個月。甲 與乙約定：若3個月後乙未通過試用，該房屋之使用借貸失其效力。若乙3個月後不幸未通過試用，關 於該屋之借貸，發生何種效力？', '["解除條件成就", "停止條件成就", "終期屆至", "始期屆至"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00720', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於民法所規定物之敘述，何者錯誤？', '["汽車之輪胎，為動產", "土地上之行道樹，為獨立不動產", "柴犬為動產", "臨時敷設之輕便軌道，為動產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00721', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '甲欲開設文創商場，委託乙完成該商場之室內裝潢。甲、乙間訂立何種契約？', '["承攬契約", "買賣契約", "委任契約", "僱傭契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00722', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-111-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '甲開車闖紅燈，撞死正一邊過馬路一邊滑手機之乙。下列敘述，何者錯誤？', '["甲得主張乙若專心過馬路，就會看到甲的車，故乙對損害之發生與有過失，甲無須賠償", "如果甲受僱於丙公司，負責送貨，甲於送貨途中撞死乙，則乙之配偶丁得向丙求償", "乙之配偶丁安葬乙後，得向甲請求賠償喪葬費", "乙之配偶丁得向甲請求慰撫金"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:18+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "511", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
